#include <iostream>
#define MAX 100
using namespace std;

class Stack {
    int top;
    int arr[MAX];
public:
    Stack() { top = -1; }

    bool push(int x) {
        if (top >= (MAX - 1)) return false; // Stack overflow
        arr[++top] = x;
        return true;
    }

    int pop() {
        if (top < 0) return -1; // Stack underflow
        return arr[top--];
    }

    int peek() {
        if (top < 0) return -1;
        return arr[top];
    }
};

int main() {
    Stack s;
    s.push(10);
    s.push(20);
    cout << "Top element: " << s.peek() << endl; // Output: 20
    cout << "Popped element: " << s.pop() << endl; // Output: 20
    return 0;
}
