#include <iostream>
#define SIZE 5
using namespace std;

class Queue {
    int arr[SIZE];
    int front, rear;
public:
    Queue() { front = 0; rear = 0; }

    bool enqueue(int x) {
        if (rear == SIZE) return false; // Queue full
        arr[rear++] = x;
        return true;
    }

    int dequeue() {
        if (front == rear) return -1; // Queue empty
        return arr[front++];
    }
};

int main() {
    Queue q;
    q.enqueue(10);
    q.enqueue(20);
    cout << "Dequeued: " << q.dequeue() << endl; // Output: 10
    return 0;
}
